net/amorcyc/article/details/105506315", "source": "csdn"}]}, {"node_id": "结构化数据", "mastery_score": 54.0, "priority": 6, "llm_priority": 2, "resources": [{"type": "video", "title": "【打工人必会技能】从纯文本到结构化数据", "url": "https://www.bilibili.com/video/BV1Lz4y1z7oE", "source": "bilibili"}, {"type": "blog", "title": "<em>结构化数据</em>、半<em>结构化数据</em>和非<em>结构化数据</em>分析", "url": "https://blog.csdn.net/weixin_45847421/article/details/115499725", "source": "csdn"}]}, {"node_id": "非结构化数据", "mastery_score": 58.0, "priority": 7, "llm_priority": 3, "resources": [{"type": "video", "title": "非结构化数据到底应该如何管理？", "url": "https://www.bilibili.com/video/BV1aZ4y1q7ZR", "source": "bilibili"}, {"type": "blog", "title": "<em>结构化数据</em>、半<em>结构化数据</em>和<em>非结构化数据</em>分析", "url": "https://blog.csdn.net/weixin_45847421/article/details/115499725", "source": "csdn"}]}], "llm_advice": "建议从数据管理过程开始，理解数据生命周期和基础概念，再逐步学习结构化与非结构化数据处理，为数据集成打下基础。掌握HDFS数据操作后，能更好地处理分布式存储，再学习数据清洗提升数据质量。这样由浅入深，逐步构建完整知识体系。对于数据管理过程，建议先阅读教材梳理流程；HDFS操作可结合实践项目加深理解。加油，你已经走在大数据学习的正确道路上！", "llm_order_reason": "从基础概念到技术实现，逐步构建大数据处理的知识体系。"}','2026-04-05T15:32:12.853168');
INSERT INTO "learning_plans" VALUES('zyh','zyh_path_20260405_155945.json','','path','{"username": "zyh", "generated_at": "2026-04-05T15:59:45.387486", "status": "active", "weak_nodes": [{"node_id": "数据管理过程", "mastery_score": 29.0, "priority": 1, "llm_priority": 1, "resources": [{"type": "video", "title": "【南京大学】数据管理基础", "url": "https://www.bilibili.com/video/BV1S7411M7pu", "source": "bilibili"}, {"type": "blog", "title": "<em>数据管理</em>基础知识", "url": "https://blog.csdn.net/qq_33840251/article/details/132093448", "source": "csdn"}]}, {"node_id": "HDFS数据操作", "mastery_score": 34.5, "priority": 2, "llm_priority": 5, "resources": [{"type": "video", "title": "实验2 HDFS基本操作", "url": "https://www.bilibili.com/video/BV1kwE7zSEhr", "source": "bilibili"}, {"type": "blog", "title": "<em>HDFS</em>-<em>操作</em>", "url": "https://blog.csdn.net/2403_88719012/article/details/143508208", "source": "csdn"}]}, {"node_id": "数据清洗", "mastery_score": 40.0, "priority": 3, "llm_priority": 6, "resources": [{"type": "video", "title": "【Python 数据清洗】用Python给数据洗澡澡~ |数据分析|数据清洗|数据预处理|", "url": "https://www.bilibili.com/video/BV1qb411M7ew", "source": "bilibili"}, {"type": "blog", "title": "spark<em>数据清洗教程</em>", "url": "https://blog.csdn.net/2401_87250241/article/details/146949421", "source": "csdn"}]}, {"node_id": "Spark架构", "mastery_score": 47.0, "priority": 4, "llm_priority": 7, "resources": [{"type": "video", "title": "03_Spark架构原理", "url": "https://www.bilibili.com/video/BV1yv4y1S72s", "source": "bilibili"}, {"type": "blog", "title": "<em>Spark</em>入门<em>教程</em>", "url": "https://blog.csdn.net/2501_90817125/article/details/148559524", "source": "csdn"}]}, {"node_id": "数据集成", "mastery_score": 47.5, "priority": 5, "llm_priority": 4, "resources": [{"type": "video", "title": "14.数据集成", "url": "https://www.bilibili.com/video/BV1UJ4m1H7Xi", "source": "bilibili"}, {"type": "blog", "title": "<em>数据</em>分析实战45讲（12） <em>数据集成</em>", "url": "https://blog.csdn.net/amorcyc/article/details/105506315", "source": "csdn"}]}, {"node_id": "结构化数据", "mastery_score": 54.0, "priority": 6, "llm_priority": 2, "resources": [{"type": "video", "title": "OnekeyComp-Comp2结构化数据建模", "url": "https://www.bilibili.com/video/BV1Eb421i7nn", "source": "bilibili"}, {"type": "blog", "title": "<em>结构化数据</em>、半<em>结构化数据</em>和非<em>结构化数据</em>分析", "url": "https://blog.csdn.net/weixin_45847421/article/details/115499725", "source": "csdn"}]}, {"node_id": "非结构化数据", "mastery_score": 58.0, "priority": 7, "llm_priority": 3, "resources": [{"type": "video", "title": "非结构化数据到底应该如何管理？", "url": "https://www.bilibili.com/video/BV1aZ4y1q7ZR", "source": "bilibili"}, {"type": "blog", "title": "<em>结构化数据</em>、半<em>结构化数据</em>和<em>非结构化数据</em>分析", "url": "https://blog.csdn.net/weixin_45847421/article/details/115499725", "source": "csdn"}]}], "llm_advice": "学习顺序合理：先掌握数据管理全流程，再理解数据类型差异，通过数据集成建立系统思维，HDFS作为存储基础需先掌握，数据清洗是后续分析的前提。建议：1. 数据管理过程通过绘制数据生命周期流程图强化记忆，结合案例分析流程节点；2. HDFS操作先搭建单机集群实践文件读写，重点理解数据块副本机制。坚持按此顺序学习，逐步夯实基础，你一定能掌握大数据核心技能！", "llm_order_reason": "先掌握数据管理的整体流程，再理解数据类型差异，接着学习如何整合数据，随后学习分布式存储（HDFS）操作，进行数据清洗后，最后使用Spark架构处理数据。"}','2026-04-05T15:59:45.389064');
INSERT INTO "learning_plans" VALUES('Q','Q_plan_20251025_213311.json','data\learning_plans\Q_plan_20251025_213311.json','global','[{"date": "2025-10-25", "priority": "基础知识", "topic": "学习大数据分析", "deadline": "2025-11-01", "materials": ["当然，以下是一个简明的、高质量的推荐书籍、文章或资源列表，以帮助人们学习''学习大数据分析''：", "### 中文资源", "1. **《大数据分析实战》** - 作者：李明", "   - 这本书通过实际案例介绍了大数据分析的基本概念和工具，适合初学者。", "2. **《Python大数据分析》** - 作者：W. John Chambers等", "   - 本书详细介绍了如何使用Python进行大数据分析，包括数据清洗、分析和可视化。", "3. **《大数据技术与应用》** - 作者：张三", "   - 这本书涵盖了大数据技术的各个方面，从基础理论到实际应用，适合系统学习。", "### 英文资源", "1. **\"Big Data: A Revolution That Will Transform How We Live, Work, and Think\"** - by Viktor Mayer-Schönberger and Kenneth Cukier", "   - 这本书是大数据领域的经典之作，介绍了大数据如何改变我们的生活和工作方式。", "2. **\"Python for Data Analysis\"** - by Wes McKinney", "   - 作者Wes McKinney是Pandas库的创建者，这本书详细介绍了如何使用Pandas进行数据分析。", "3. **\"Data Science from Scratch\"** - by Joel Grus", "   - 这本书从基础开始，介绍了数据科学的各个方面，包括统计学、编程和机器学习。", "### 在线课程和资源", "1. **Coursera - \"Data Science Specialization\"** - by Johns Hopkins University", "   - 这个专项课程涵盖了数据科学的各个方面，包括大数据分析。", "2. **edX - \"MicroMasters® in Statistics and Data Science\"** - by Massachusetts Institute of Technology", "   - 这个微硕士课程提供了系统的统计和数据科学教育，适合深入学习。", "3. **Kaggle Learn**", "   - Kaggle提供的免费互动课程，涵盖数据科学和机器学习的基本概念。", "### 工具与软件", "1. **Apache Hadoop**", "   - 一个开源的分布式计算平台，广泛用于大数据存储和处理。", "2. **Apache Spark**", "   - 另一个开源的分布式计算系统，适用于大规模数据处理和机器学习。", "3. **Tableau**", "   - 一个强大的数据可视化工具，帮助用户理解和展示数据。", "### 社区与论坛", "1. **Stack Overflow**", "   - 一个编程问答社区，可以找到许多关于大数据分析的解决方案和讨论。", "2. **Reddit - r/datascience**", "   - 一个活跃的数据科学社区，分享最新的研究、工具和项目。", "3. **Hadoop & Spark Community**", "   - 专门的社区论坛，可以交流关于Hadoop和Spark的使用经验和问题。", "希望这些资源能帮助您更好地学习大数据分析！"]}]','2026-04-05T16:09:15.763918');
INSERT INTO "learning_plans" VALUES('Q','Q_plan_20251113_155856.json','data\learning_plans\Q_plan_20251113_155856.json','global','[{"date": "2025-11-13", "priority": "拓展创新", "topic": "了解机器学习", "materials": ["了解机器学习", "1. 书籍", "•  《机器学习》（周志华）：中文经典教材，系统覆盖监督、无监督与强化学习。", "•  《深度学习》（Ian Goodfellow 等）：涵盖神经网络基础与高级结构，适合进阶学习。", "•  《统计学习方法》（李航）：中文权威教材，详述SVM、集成学习等经典算法。", "2. 文章与博客", "•  机器之心：涵盖AI与ML前沿进展，中文为主。", "•  知乎专栏：众多从业者分享实战经验与学习路径。", "•  CSDN/掘金：技术博客集中地，包含大量代码示例与项目实践。", "3. 在线课程", "•  网易云课堂：《机器学习实战》《深度学习入门》", "•  腾讯课堂：《AI基础》《推荐系统工程》", "•  慕课网：《特征工程》《模型调优》", "4. 开源项目与代码库", "•  GitHub：搜索“machine-learning”，关注Star数高的项目（如TensorFlow、PyTorch示例）。", "•  Kaggle Kernel：实战性Notebook示例，涵盖数据预处理与模型训练。", "5. 工具与平台", "•  Google Colab：免费GPU资源，支持Notebook交互式学习。", "•  Hugging Face：NLP模型与数据集，适合特征工程与模型微调。", "6. 社区与论坛", "•  知乎 Live：与专家互动提问。", "•  掘金圆桌：分享学习心得与项目经验。", "•  机器学习社区（QQ/微信群）：实时交流与资源互换。", "7. 行业报告与白皮书", "•  阿里云天池大赛：实战数据集与竞赛规则解析。", "•  Gartner 报告：了解行业趋势与预测。", "8. 学术会议与论文", "•  NeurIPS/ICML/AAAI：检索相关论文，关注因果推断与图神经网络方向。", "•  顶会论文解读：关注因果推理与自动化特征工程相关研究。", "9. 实践项目", "•  小型项目：如鸢尾花分类、客户细分项目，结合代码与文档。", "•  Kaggle 比赛：参与客户流失预测项目，提交解决方案。", "10. 其他资源", "•  Bilibili：搜索“机器学习”，获取视频教程。", "•  微信公众号：推送学习笔记与行业应用案例。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同工作，确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Size。", "•  跨数据中心一致性：", "○  在多地域部署中，通过最终一致性策略平衡性能与数据一致性。", "•  幂等性（Idempotence）", "•  副本同步机制：DataNode 与 NameNode 协同确保写入成功与数据一致性。", "•  性能瓶颈分析：", "○  NameNode 元数据管理瓶颈（可通过 Federation 拆分或内存优化缓解。", "○  数据写入性能：启用 Pipeline 写入与数据压缩减少 I/O 压力。", "•  副本重建影响：", "○  副本重建期间写入吞吐量下降，需合理配置副本因子与 Block Si