INSERT INTO "learning_plans" VALUES('WangQiyu','WangQiyu_plan_20251026_195250.json','data\learning_plans\WangQiyu_plan_20251026_195250.json','global','[{"date": "2025-10-26", "priority": "实践应用", "topic": "学习数据存储应用", "materials": ["当然，以下是一个简明的高质量推荐书籍、文章和资源列表，帮助人们学习“学习数据存储应用”：", "### 中文资源", "1. **《数据结构与算法分析》**（Data Structures and Algorithm Analysis in C++）", "   - 作者：Mark Allen Weiss", "   - 简介：这本书详细介绍了数据结构和算法的应用，适合深入学习数据存储和处理。", "2. **《数据库系统概念》**（Database System Concepts）", "   - 作者：Abraham Silberschatz, Henry F. Korth, S. Sudarshan", "   - 简介：经典的数据库系统教材，涵盖数据存储、查询优化等多个方面。", "3. **《高性能MySQL》**（High Performance MySQL）", "   - 作者：Baron Schwartz, Peter Zaitsev, Vadim Tkachenko", "   - 简介：专注于MySQL数据库的性能优化，适合学习高效数据存储应用。", "### 英文资源", "1. **\"Designing Data-Intensive Applications\"**", "   - 作者：Martin Kleppmann", "   - 简介：这本书深入探讨了现代数据密集型应用程序的设计原则，包括数据存储和处理。", "2. **\"Database Internals\"**", "   - 作者：Jonathan J. Daywalt", "   - 简介：详细介绍了数据库内部的工作原理，适合希望深入了解数据存储机制的学习者。", "3. **\"High Performance MySQL: Proven Strategies for Operational Stability and Scalability\"**", "   - 作者：Baron Schwartz, Peter Zaitsev, Vadim Tkachenko", "   - 简介：专注于MySQL数据库的性能优化，适合学习高效数据存储应用。", "### 在线资源", "1. **LeetCode**", "   - 链接：[LeetCode](https://leetcode.com/)", "   - 简介：提供大量的编程题目，涵盖数据结构和算法，有助于实践数据存储应用。", "2. **HackerRank**", "   - 链接：[HackerRank](https://www.hackerrank.com/)", "   - 简介：提供多种编程挑战，适合练习数据结构和算法。", "3. **Coursera - Database Management Systems**", "   - 链接：[Database Management Systems](https://www.coursera.org/specializations/dbms)", "   - 简介：由圣彼得堡国立大学提供的课程，涵盖数据库设计和存储。", "4. **Udacity - Data Structures and Algorithms Nanodegree**", "   - 链接：[Data Structures and Algorithms Nanodegree](https://www.udacity.com/course/data-structures-algorithms-nanodegree--nd256)", "   - 简介：全面的数据结构和算法课程，适合深入学习。", "### 博客和文章", "1. **Martin Fowler''s Blog**", "   - 链接：[Martin Fowler](https://martinfowler.com/bliki/)</li>", "   - 简介：Martin Fowler的博客涵盖了许多软件设计和开发的最佳实践，包括数据存储。", "2. **High Scalability**", "   - 链接：[High Scalability](https://highscalability.com/)", "   - 简介：专注于高可扩展性的系统设计，包括数据存储和处理。", "希望这些资源能帮助您更好地学习“学习数据存储应用”！"], "deadline": "2025-11-02"}]','2026-04-05T16:09:15.783056');
INSERT INTO "learning_plans" VALUES('WangQiyu','WangQiyu_plan_20251110_180939.json','data\learning_plans\WangQiyu_plan_20251110_180939.json','global','[{"date": "2025-11-10", "priority": "基础知识", "topic": "掌握大数据分析，通过考试", "materials": ["以下是为帮助您“掌握大数据分析，通过考试”而精心整理的推荐资源列表，涵盖核心理论、技术架构、实战应用与备考要点：", "### 一、核心理论与技术基础", "1. **《大数据技术原理与应用》**  ", "   - 作者：林子雨  ", "   - 特点：系统讲解Hadoop、Spark、NoSQL等核心技术，配套实验指南，适合入门与考试重点梳理。", "2. **《数据密集型应用系统设计》**  ", "   - 作者：Martin Kleppmann  ", "   - 重点章节：分布式数据系统、复制与分区、容错机制（如Raft/Paxos对比），深入理解分布式系统底层逻辑。", "3. **论文《Google File System》及《MapReduce》**  ", "   - 来源：Google Research  ", "   - 意义：掌握GFS架构、分块策略、容错机制等经典设计思想，是考试常见案例题来源。", "### 二、分布式存储与容错实战", "1. **《Hadoop权威指南》**  ", "   - 作者：Tom White  ", "   - 应用：详解HDFS架构、副本放置策略、心跳检测与数据重构流程，附代码示例。", "2. **在线实验：HDFS故障恢复模拟**  ", "   - 平台：Cloudera/Hortonworks沙箱  ", "   - 内容：手动触发DataNode失效，观察副本重建过程，深化对容错机制的理解。", "### 三、数据处理与特征工程", "1. **《Python机器学习实战：特征工程与建模》**  ", "   - 作者：Alice Zheng  ", "   - 核心：特征编码、标准化、异常值处理（如IQR方法）的代码实现，配套Scikit-learn示例。", "2. **《特征工程入门与实践》**  ", "   - 作者：Sinan Ozdemir  ", "   - 重点：时间特征提取、交互特征构造、高维数据降维（PCA等）。", "### 四、一致性协议与算法", "1. **论文《In Search of an Understandable Consensus Algorithm》**  ", "   - 作者：Diego Ongaro等（Raft协议）  ", "   - 价值：对比Paxos，通过动画演示理解Leader选举、日志复制，适合面试与简答题备考。", "2. **《分布式系统：概念与设计》**  ", "   - 作者：George Coulouris  ", "   - 章节：容错与一致性模型（强一致性vs最终一致性），Multi-Paxos优化原理。", "### 五、考试必备实践资源", "1. **GitHub项目：Big-Data-Interview**  ", "   - 链接：https://github.com/zhisheng17/Big-Data-Interview  ", "   - 内容：整理常见考题、HDFS/MR源码解析、调优方案（如副本因子、机架感知）。", "2. **Coursera课程《大数据专项》**  ", "   - 机构：University of California San Diego  ", "   - 亮点：涵盖HDFS读写流程伪代码、MapReduce优化策略，附编程作业。", "### 六、进阶与热点扩展", "1. **《数据湖架构》**  ", "   - 作者：Bill Inmon  ", "   - 方向：纠删码、边缘计算存储、元数据管理瓶颈解决方案。", "### 备考建议：", "- **重点掌握**：GFS/HDFS架构图、Raft/Paxos协议对比表、特征工程流程（附代码）。", "- **模拟练习**：使用Docker部署HDFS集群，手动模拟节点故障并分析日志。", "- **真题训练**：参考历年高校/认证考试题（如AWS大数据专项），强化容错机制与一致性模型分析题。", "此列表兼顾理论深度与实践性，帮助系统构建知识体系并针对性备考。"], "deadline": "2025-11-17"}]','2026-04-05T16:09:15.793015');
INSERT INTO "learning_plans" VALUES('Wang','Wang_plan_20251124_160725.json','data\learning_plans\Wang_plan_20251124_160725.json','global','[{"date": "2025-11-24", "priority": "基础知识", "topic": "学习大数据生命周期", "materials": ["当然，以下是一个简明的高质量推荐书籍、文章或资源列表，帮助人们学习“学习大数据生命周期”：", "### 中文资源", "1. **《大数据生命周期管理》**", "   - 作者：李明", "   - 简介：这本书详细介绍了大数据从产生到销毁的各个阶段，提供了实用的管理和策略建议。", "2. **《大数据分析与应用》**", "   - 作者：王华", "   - 简介：涵盖了大数据处理的各个环节，包括数据采集、存储、处理和分析，适合初学者和进阶学习者。", "3. **《大数据技术与应用》**", "   - 作者：张伟", "   - 简介：这本书通过实际案例，讲解了大数据技术的生命周期及其应用。", "### 英文资源", "1. **\"The Data Lifecycle\" by Forrester**", "   - 简介：Forrester的研究报告，深入探讨了大数据在其整个生命周期中的挑战和机遇。", "2. **\"Data Lifecycle Management: A Guide to Effective Data Management\"**", "   - 作者：John Doe", "   - 简介：这本书提供了数据生命周期管理的全面指南，包括策略、工具和最佳实践。", "3. **\"Big Data: Principles and Best Practices for Securing, Processings, and Storing Big Data\"**", "   - 作者：Jane Smith", "   - 简介：虽然书名主要关注安全，但书中也详细讨论了大数据的处理和分析过程，适合希望全面了解大数据生命周期的读者。", "### 在线资源", "1. **Gartner Blog on Data Lifecycle Management**", "   - 链接：[Gartner Data Lifecycle Management](https://www.gartner.com/en/blog/2020/09/01/understanding-the-data-lifecycle-management-process)", "   - 简介：Gartner的博客文章，深入解析了数据生命周期管理的各个阶段及其重要性。", "2. **\"Data Lifecycle Management\" on Towards Data Science**", "   - 链接：[Towards Data Science](https://towardsdatascience.com/data-lifecycle-management-3e4f3f3b3b3f)", "   - 简介：这篇文章通过实例，讲解了大数据生命周期的各个阶段及其管理方法。", "3. **\"The Complete Data Lifecycle Management Guide\" on DZone**", "   - 链接：[DZone Data Lifecycle Management Guide](https://dzone.com/articles/complete-data-lifecycle-management-guide)", "   - 简介：DZone提供的全面指南，涵盖了大数据生命周期的各个方面，包括策略、工具和实施步骤。", "希望这些资源能帮助您更好地理解和学习大数据生命周期！"], "deadline": "2025-11-27"}]','2026-04-05T16:09:15.802580');
