INSERT INTO "user_states" VALUES('zyh','{"industry_latest_task_id": "a8a16ab3ab0c4bcd9979b3fa41fa86f3", "industry_latest_task_snapshot": {"task_id": "a8a16ab3ab0c4bcd9979b3fa41fa86f3", "task_type": "analyze", "status": "completed", "message": "分析完成。", "meta": {"step": 5}, "result": {"jobs": [{"title": "Data Analyst, AI & Data, Technology Consulting", "company": "EY", "salary": "面议", "location": "Raffles Quay", "experience": "1-3年", "education": "硕士及以上", "description": "At EY, we develop you with future-focused skills and equip you with world-class experiences. We empower you in a flexible environment, and fuel you and your extraordinary talents in a diverse and inclusive culture of globally connected teams.\n\nWe work together across our full spectrum of services and skills powered by technology and AI, so that business, people and the planet can thrive together.\n\nWe’re all in, are you?\n\nJoin EY and shape your future with confidence.\n\n**About the opportunity**\n\nEY AI & Data is the data and advanced analytics capability within EY Asia-Pacific, with over 500 specialist employees working across multiple industry sectors. We implement information-driven strategies, data platforms and advanced data analytics solution systems that help grow, optimize and protect client organizations. We go beyond strategy and provide end to end design, build and implementation of real-life data environments and have some of the best architects, project managers, business analysts, data scientists, big data engineers, developers and consultants in the region. We are looking for a Data Analyst within the AI & Data team in our Singapore office. This role is offered on a flexible full-time basis.\n\n**Your key responsibilities:**\n\n* Collaborate with cross-functional teams to gather requirements, define data-related technical issues, and provide solutions.\n* Create informative and interactive dashboards and reports in Power BI, Qlik or similar tools to meet the needs of the business.\n* Write advanced SQL queries for data manipulation and retrieval from relational databases.\n* Develop and optimize data models within the dashboarding tool for reporting and analytics.\n* Perform data extraction, transformation, and loading of large and complex data sets from various source systems.\n* Ensure data quality and integrity by implementing data validation and testing within ETL processes.\n* Monitor ETL jobs, troubleshoot any issues, and perform performance tuning to improve data processing.\n* Stay current with the latest technologies and best practices in data engineering and business intelligence\n\n**Skills & attributes for success:**\n\n* Experience of data-driven organizational transformation supported by data insights and good story telling\n* Experience in business intelligence, data warehousing/platform, or data strategy projects\n* Experience in ETL development and Data Analysis\n* Knowledge and experience in data governance, data security, and privacy practices\n* Exceptional communication, documentation and presentation skills and stakeholder management experiences\n\n**To qualify for the role, you must have**\n\n* Bachelor’s degree in Computer Science, Information Technology, or a related field.\n* Minimum of 1 year of experience as a Data Analyst with experience in ETL development and data warehousing.\n\n* Prior experience with Azure Data Factory, including building and optimizing data pipelines, is preferred.\n* Strong proficiency in writing and optimizing SQL queries.\n* Expertise in popular commercial BI tools, such as Power BI, Qlik.\n* Familiarity with data governance, data security, and privacy practices.\n* Excellent problem-solving skills and attention to detail.\n* Strong communication and collaboration skills to work effectively with both technical and non-technical team members.\n\n**Ideally, you’ll also have**\n\n* Dashboarding experience with Power BI, Qlik or equivalent tools\n* Experience in engaging with both technical and non-technical stakeholders\n* Consulting experience and background, including engaging directly with clients\n\n**What we look for**\n\n* Highly motivated individuals with excellent problem-solving skills and the ability to prioritize shifting workloads in a rapidly changing industry.\n* An effective communicator, you’ll be a confident leader equipped with strong people management skills and a genuine passion to make things happen in a dynamic organization.\n\n**What we look for**\n\nHighly motivated individuals with excellent problem-solving skills and the ability to prioritize shifting workloads in a rapidly changing industry. An effective communicator, you’ll be a confident team player that collaborates with people from various teams while looking to develop your career in a dynamic organization.\n\n**What working at EY offers**\n\nEY offers a competitive remuneration package where you’ll be rewarded for your individual and team performance. We are committed to being an inclusive employer and are happy to consider flexible working arrangements. Plus, we offer:\n\n  \n\n* Continuous learning: You’ll develop the mindset and skills to navigate whatever comes next.\n* Success as defined by you: We’ll provide the tools and flexibility, so you can make a meaningful impact, your way.\n* Transformative leadership: We’ll give you the insights, coaching and confidence to be the leader the world needs.\n* Diverse and inclusive culture: You’ll be embraced for who you are and empowered to use your voice to help others find theirs.\n\n**Company description**\n\nEY is building a better working world by creating new value for clients, people, society and the planet, while building trust in capital markets.\n\nEnabled by data, AI and advanced technology, EY teams help clients shape the future with confidence and develop answers for the most pressing issues of today and tomorrow.\n\nEY teams work across a full spectrum of services in assurance, consulting, tax, strategy and transactions. Fueled by sector insights, a globally connected, multi-disciplinary network and diverse ecosystem partners, EY teams can provide services in more than 150 countries and territories.\n\nAll in to shape the future with confidence.", "requirements": "You must have 1 year of experience as a Data Analyst with ETL development and data warehousing. You should also have knowledge in data governance, data security, and privacy practices. Prior experience with Azure Data Factory is preferred.", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Big Data Analyst", "relevance_score": 44, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "标题命中: data", "描述命中: data", "标题命中: analyst", "描述命中: analyst", "描述命中: big", "描述命中: science", "描述命中: business", "描述命中: intelligence", "描述命中: insights", "描述命中: specialist"], "market_country": "新加坡", "skill_evidence": [{"name": "Power BI", "evidence": "Create informative and interactive dashboards and reports in Power BI, Qlik or similar tools to meet the needs of the..."}, {"name": "SQL", "evidence": "Write advanced SQL queries for data manipulation and retrieval from relational databases."}, {"name": "Azure Data Factory", "evidence": "Prior experience with Azure Data Factory, including building and optimizing data pipelines, is preferred."}, {"name": "Data Governance", "evidence": "Knowledge and experience in data governance, data security, and privacy practices."}, {"name": "Data Security", "evidence": "Knowledge and experience in data governance, data security, and privacy practices."}, {"name": "Data Privacy", "evidence": "Knowledge and experience in data governance, data security, and privacy practices."}, {"name": "ETL Development", "evidence": "Experience in ETL development and Data Analysis."}, {"name": "Data Warehousing", "evidence": "Experience in business intelligence, data warehousing/platform, or data strategy projects."}, {"name": "Data Modeling", "evidence": "Develop and optimize data models within the dashboarding tool for reporting and analytics."}], "skills": ["Power BI", "SQL", "Azure Data Factory", "Data Governance", "Data Security", "Data Privacy", "ETL Development", "Data Warehousing", "Data Modeling"]}, {"title": "Associate IT Business Analyst", "company": "AstraZeneca", "salary": "面议", "location": "Kallang", "experience": "不限", "education": "不限", "description": "c\n\n**Job Title: Associate IT Business Analyst**\n\nCareer Level: E\n\n**Introduction to role:**\n\nBe part of history in the making. AstraZeneca is building its first‑ever biologics manufacturing campus in Singapore—a USD 1.5 billion, state‑of‑the‑art hub that unites end‑to‑end Antibody–Drug Conjugate (ADC) capabilities under one roof: small‑molecule chemical API production, large‑molecule antibody manufacturing, conjugation, and fill‑and‑finish (including sterile filling and lyophilization). Powered by advanced digitalization, automation, and artificial intelligence for autonomous manufacturing—and targeting carbon neutrality—this next‑generation site will set a new benchmark for environmentally responsible biologics production.\n\nAre you ready to turn data, cognitive technologies, and robotic processes into measurable business outcomes that help deliver life-changing medicines? Do you thrive at the intersection of discovery and delivery—shaping ideas into production solutions that improve quality, safety and productivity?\n\nIn this role, you will collaborate with product leaders, data scientists, engineers, and operational teams to pinpoint high-value opportunities. You will build compelling business justifications and speed up the development of intelligent systems and automated solutions from concept to scale. Your work will help reduce cycle times, enhance decision quality and unlock efficiencies that ultimately support patients and the business. You will expand your skills in a culture that prizes curiosity and continuous learning, with the backing to experiment, iterate and deliver.\n\nFrom day one, you will lead discovery, structure experiments, and orchestrate the path to production with strong governance. You will help set guardrails for responsible AI, support operational frameworks involving human participation, and establish clear metrics so benefits are tracked and realized. This is a chance to build capabilities that endure—while shaping your own development through hands-on, outcomes-focused work.\n\n**Accountabilities:**\n\n* Discovery and Opportunity Shaping: Collaborate with partners to understand priority problems. Find and prioritize opportunities in machine intelligence and process automation that support strategy and responsible AI principles. Set guardrails and success metrics to maintain value and compliance.\n* Translate complex business demands into clear analysis and solution builds. Evaluate data readiness. Share model results and change effects to support safer decisions and faster adoption.\n* Collaborate with engineering and data science partners to develop demonstrations of value. Run rapid experiments and convert successful pilots into resilient production solutions.\n* Value Cases and Benefits Realization: Build return on investment and benefits models with baselines and measurement plans; track improvements in productivity, quality and safety post launch to evidence outcomes.\n* Architecture and ML Ops Collaboration: Coordinate with platform, integration, data and observability teams; align to corporate architectural standards to improve process performance and digital maturity.\n* Lead structured compose sessions to gather functional and technical requirements, define data labeling needs and agree acceptance criteria.\n* Analytics and Insights: Capture and analyze usage, evolving data patterns, and model-generated outcomes; support A/B testing; generate insights for iterative optimization and decision‑making.\n* Change and Adoption: Drive communications, training and AI literacy; shape responsible use guidelines and human‑in‑the‑loop models to secure adoption and sustained value.\n* Planning and Delivery: Build coordinated plans and handle stage gates from discovery through deployment and hypercare, encompassing data integration, model verification, and launch readiness.\n* Collaborator Management and Governance: Map customers; run clear communications and status for executives and teams; surface AI risks, performance and benefits; establish and run working groups and steering forums; ensure compliance with GxP, privacy, cybersecurity, ethical AI, audit and model governance with evidence and explain ability artifacts.\n* Handle a clear and verifiable scope along with change management that covers retraining, drift management, and feature updates. Oversee RAID to maintain timelines across data sources, model pipelines, and integration layers.\n* Financial Stewardship: Develop and lead all aspects of budgets, forecasts and actuals covering costs associated with cloud resource consumption, AI service charges and licensing.\n* Operational Readiness and Cutover: Orchestrate readiness, cutover, hypercare, training and transition to BAU or an equivalent level of experience with ML Ops transfer, oversight and lifecycle management.\n* Keep accurate metrics and dashboards. Provide clear updates to governance bodies. Support data-driven decisions through self-service analytics and AI-assisted reporting. Develop and refine Agile, hybrid, or waterfall approaches using innovation sprints, labs, and creative thinking.\n* Site and Global Coordination: Align site execution to global standards and frameworks; lead all aspects of localization while preserving platform guardrails.\n\n**Essential Skills/Experience:**\n\n* Business Discovery & AI Opportunity Identification: Engage collaborators to understand and prioritize business needs to drive operational efficiencies. Proactively identify AI/ML and automation use cases aligned to strategic objectives and ethical AI principles.\n* Data- and technology-based Solution Composition: Translate sophisticated business requirements into clear, actionable analysis, solution compositions, and decisions. Communicate model performance, data readiness, and change implications to address business risks and issues.\n* Innovation Pipeline Contribution: Give innovative ideas and aligned with AZ IT strategy. Collaborate with AZ IT partners to incubate proofs of value, run rapid experiments, and transition successful pilots into production.\n* Value Cases & Benefits Realization: Develop and shape cases including return on investment, productivity uplift, quality/safety improvements, and benefits tracking for AI-enabled initiatives that meet agreed business outcomes.\n* Architecture, Data, and ML Ops Collaboration: Coordinate with IT capability teams to identify crucial capabilities (Data platform, Integration patterns, ML Ops, Observability) required for successful outcomes. Align solutions to enterprise patterns and improve process performance and digital maturity.\n* Design Workshops & Experimentation: Lead workshops to elicit functional and technical requirements, label data needs, define guardrails, and agree on successful metrics for AI solutions.\n* Analytics & Insights Capture and analyse information from relevant sources to report data trends and model insights, enabling informed decision-making and continuous improvement. Support A/B testing and iterative optimization.\n* Change & Adoption: Actively engage collaborators and share knowledge with delivery teams. Support communication plans and organizational change for projects, including AI literacy, responsible use guidelines, and human-in-the-loop operating models.\n* Planning & Delivery: Develop integrated schedules and manage stage gates from discovery to deployment and hyper care, including data onboarding, model validation, and launch.\n* Partner Engagement: Map collaborators, run clear comms and status reporting for execs and teams, surface AI risks/performance/benefits, and facilitate decisions.\n* Scope & Change Control: Maintain a clear, testable scope; run CRs; assess time/cost/quality impacts, including model retraining, drift management, and feature updates.\n* Governance & Compliance: Establish and run project governance routines (steerco, working groups). Ensure adherence to quality, GxP, data privacy cybersecurity, ethical AI, model governance, audit requirements; maintain proof of compliance and explain ability documentation.\n* Risk/Issue/Dependency Management: Maintain RAID logs; quantify impact, drive mitigations. Handle dependencies across data sources, model pipelines, and integration layers to protect timelines.\n* Budget & Financials: Create and handle budgets, forecasts, and actuals to keep project within budget including cloud consumption, AI service cost, and licensing.\n* Operational Readiness & Cutover: Manage readiness, transition activities, hyper care, training, and handover to BAU, including ML Ops handover, monitoring, and model lifecycle management.\n* Maintain accurate project metrics and dashboards. Provide timely, transparent reports to governance bodies. Use interactive analytics platforms and automated report generation to advise decisions.\n* Methodology & Ways of Working :Apply appropriate delivery approach (Agile, hybrid, or waterfall). Ensure ceremonies/cadence and continuously improve processes with innovation sprints, labs, and Design Thinking practices.\n* Security & Privacy by Design: Embed security requirements; conduct risk assessments; ensure data classification and privacy controls from the outset, including PII handling, model security, adversarial robustness, and responsible data use.\n* Site & Global Coordination: Align site-level execution with global standards and architectures; handle localization while preserving enterprise consistency and AI platform guardrails.\n\n**Desirable Skills/Experience:**\n\n* Experience in life sciences, healthcare or other regulated environments, with familiarity applying model governance and explain ability in practice\n* Exposure to modern cloud and data platforms (e.g., Azure, AWS or GCP), Databricks or similar, and observability tools for data and ML pipelines\n* Solid understanding of SQL and/or Python for exploratory analysis and validating data readiness\n* Experience with large language models, prompt engineering and retrieval‑augmented generation in enterprise settings\n* Proficiency with split testing frameworks, product analytics and experimentation develop\n* Strong data storytelling and visualization skills using tools such as Power BI or Tableau\n* Certifications such as CBAP, PMI‑PBA, Scrum/SAFe, cloud practitioner/architect, or AI/ML specialty\n* Practical understanding of global data privacy regulations (e.g., GDPR) and cybersecurity in AI-enabled solutions\n* Financial modelling experience for return on investment and benefits tracking, including cloud consumption forecasting\n* Ability to coordinate across global teams and time zones, balancing local needs with enterprise standards\n\nWhen we put unexpected teams in the same room, we ignite ambitious thinking with the power to\n\nInspire life-changing medicines. In-person working gives us the platform we need to connect, work at pace and challenge\n\nperceptions. That''s why we work, on average, a minimum of three days per week from the office. But that\n\nDoesn''t mean we''re not flexible. We balance the expectation of being in the office while respecting individual\n\nflexibility. Join us in our unique and ambitious world.\n\n**Why AstraZeneca:**\n\nHere, technology and science meet at scale to improve patients’ lives. You will work with unexpected teams that fuel ambitious ideas, experiment with groundbreaking tools and turn them into real outcomes for colleagues and patients. We back ambition with investment and guardrails that make responsible AI the default, and we value courtesy and learning alongside high performance. You will grow through coaching, feedback and hands‑on challenges—whether that’s a hackathon prototype or deploying a production model that shortens time to critical decisions.\n\n**Call to Action:**\n\nIf you’re ready to shape high‑impact AI and automation from discovery to production while accelerating your own development, step forward and help us turn possibility into measurable value today!", "requirements": "Collaborate with product leaders, data scientists, engineers, and operational teams to pinpoint high-value opportunities. Build compelling business justifications and speed up the development of intelligent systems and automated solutions from concept to scale. Lead structured compose sessions to gather functional and technical requirements, define data labeling needs and agree acceptance criteria.", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Data Analyst", "relevance_score": 38, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "描述命中: data", "标题命中: analyst", "描述命中: analyst", "描述命中: science", "标题命中: business", "描述命中: business", "描述命中: intelligence", "描述命中: insights"], "market_country": "新加坡", "skill_evidence": [{"name": "Machine Intelligence", "evidence": "Find and prioritize opportunities in machine intelligence and process automation"}, {"name": "Process Automation", "evidence": "Find and prioritize opportunities in machine intelligence and process automation"}, {"name": "Data Readiness", "evidence": "Evaluate data readiness"}, {"name": "Model Results", "evidence": "Share model results and change effects to support safer decisions and faster adoption"}, {"name": "Data Labeling", "evidence": "Define data labeling needs"}, {"name": "A/B testing", "evidence": "Support A/B testing"}, {"name": "AI Literacy", "evidence": "Drive communications, training and AI literacy"}, {"name": "Change Management", "evidence": "Drive communications, training and AI literacy"}, {"name": "Stage Gates", "evidence": "Build coordinated plans and handle stage gates from discovery through deployment and hypercare"}, {"name": "Data Integration", "evidence": "Handle data integration"}, {"name": "Model Verification", "evidence": "Handle model verification"}, {"name": "Launch Readiness", "evidence": "Handle launch readiness"}], "skills": ["Machine Intelligence", "Process Automation", "Data Readiness", "Model Results", "Data Labeling", "A/B testing", "AI Literacy", "Change Management", "Stage Gates", "Data Integration", "Model Verification", "Launch Readiness"]}, {"title": "Staff Business Analyst IT Contract Manufacturing", "company": "Infineon Technologies", "salary": "面议", "location": "SG", "experience": "不限", "education": "不限", "description": "#WeAreIn for jobs that impact everyone''s life. Transforming data into decisions, are you ready to shape the future? As a Business Analyst on the Software & Data Science team, get ready to program the intelligence behind the chips, transform complex data into actionable insights, and create cutting-edge solutions that redefine industries and solve tomorrow''s challenges. Are you in?\n  \n  \n**Your Role**  \n  \nKey responsibilities in your new role  \n\n* Lead stakeholder engagement across OSAT and EWM (SIFO) business, operations, and IT teams to **ensure alignment on SAP Contract Manufacturing (CM) solution design, strategic priorities, and roadmap execution.**\n* **Foster effective cross-team collaboration** among technical, functional, and business groups; provided high-level ABAP guidance, reviewed solution architectures, and upheld development quality anddelivery efficiency.\n* **Drive continuous improvement and process optimisation initiatives**, aligning with industry best practices to achieve measurable operational gains.\n* **Provide strategic leadership** in analysing, designing, and configuring SAP CM processes, applying strong SAP MM expertise to address complex and cross-functional business needs.\n* **Lead end-to-end CM rollout project lifecycle activities**—including planning, design, build, testing, and deployment—leveraging extensive experience from multiple full-cycle implementations to ensure structured and risk-mitigated delivery.\n* **Manage external consultants** and service partners by setting clear expectations, tracking performance, and ensuring adherence to scope, timelines, and quality standards.\n* Research and explore **emerging technologies and digitalisation opportunities** to support innovation and operational enhancement.\n\n  \n**Your Profile**  \n  \nQualifications and skills to help you succeed  \n\n* Minimum 5 years of hands-on experience with **SAP S/4HANA MM (Material Management) or SD (Sales and Distribution)** in an enterprise environment, ideally within manufacturing, logistics, or supply-chain–related domains.\n* **Proficiency in subcontracting and outsourced manufacturing models, including complex inventory flows.** Experience with semiconductor OSAT(outsourced assembly and test) or SIFO (silicon foundry) processes is a strong plus.\n* **End-to-end SAP project exposure, including multiple phases of the project lifecycle; full-cycle implementation experience is an advantage.**\n* **Ability to work closely with ABAP developers,** with familiarity in key ABAP concepts and basic debugging techniques to support functional–technical analysis.\n* Strong analytical and problem-solving capabilities, especially when dealing with complex cross-functional processes.\n* Excellent communication and stakeholder-management skills, with the ability to articulate solutions clearly, influence decisions, and engage effectively at all levels of the organization.\n* Candidates with strong business process knowledge and high technical aptitude—motivated to grow into an SAP functional role—are also encouraged to apply.\n\n  \n**Contact:**  \nSherlene Ong\n\n**#WeAreIn for driving decarbonization and digitalization.**  \nAs a global leader in semiconductor solutions in power systems and IoT, Infineon enables game-changing solutions for green and efficient energy, clean and safe mobility, as well as smart and secure IoT. Together, we drive innovation and customer success, while caring for our people and empowering them to reach ambitious goals. Be a part of making life easier, safer and greener.  \n**Are you in?**  \n  \n**We are on a journey to create the best Infineon for everyone.**  \nThis means we embrace diversity and inclusion and welcome everyone for who they are. At Infineon, we offer a working environment characterized by trust, openness, respect and tolerance and are committed to give all applicants and employees equal opportunities. We base our recruiting decisions on the applicant´s experience and skills. Learn more about our various contact channels.  \nPlease let your recruiter know if they need to pay special attention to something in order to enable your participation in the interview process.  \nClick here for more information about Diversity & Inclusion at Infineon.", "requirements": "Lead stakeholder engagement across OSAT and EWM business, operations, and IT teams to ensure alignment on SAP Contract Manufacturing solution design. Drive continuous improvement and process optimisation initiatives. Manage external consultants and service partners by setting clear expectations and ensuring adherence to scope, timelines, and quality standards.", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Business Intelligence Analyst", "relevance_score": 38, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "描述命中: data", "标题命中: analyst", "描述命中: analyst", "描述命中: science", "标题命中: business", "描述命中: business", "描述命中: intelligence", "描述命中: insights"], "market_country": "新加坡", "skill_evidence": [{"name": "SAP S/4HANA MM", "evidence": "Minimum 5 years of hands-on experience with SAP S/4HANA MM (Material Management) or SD (Sales and Distribution) in an..."}, {"name": "SAP S/4HANA SD", "evidence": "Minimum 5 years of hands-on experience with SAP S/4HANA MM (Material Management) or SD (Sales and Distribution) in an..."}, {"name": "ABAP", "evidence": "Ability to work closely with ABAP developers, with familiarity in key ABAP concepts and basic debugging techniques to..."}, {"name": "SAP Contract Manufacturing", "evidence": "Provide strategic leadership in analysing, designing, and configuring SAP CM processes"}], "skills": ["SAP S/4HANA MM", "SAP S/4HANA SD", "ABAP", "SAP Contract Manufacturing"]}, {"title": "Manager, Data Analyst (Audit)", "company": "Sembcorp", "salary": "面议", "location": "S00", "experience": "不限", "education": "硕士及以上", "description": "**About Sembcorp**\n\nSembcorp is a leading energy and urban solutions provider headquartered in Singapore. Led by its purpose to drive energy transition, Sembcorp delivers sustainable energy solutions and urban developments by leveraging its sector expertise and global track record.\n\n**Role Overview**\n\nWe are looking for an experienced Data Analyst / Data Scientist to manage the Group Integrated Audit department’s continuous assurance program, including lead and build advanced analytics/ AI-enabled solutions that strengthen governance and unlock efficiencies within the department and across Sembcorp Group. You will be partnering closely with auditors, business stakeholders and digital teams to deliver actionable data-driven insights and AI-enabled audit use cases.\n\nThis is a hands-on, high-impact role for someone who is collaborative and passionate about applying data science and AI technologies to drive smarter, more proactive risk management.\n\n**Key Responsibilities:**\n\n* Operate and enhance the existing continuous assurance program (data analytics), including case management processes, monitoring scripts and automated data pipelines.\n* Design, build and deploy data analytics and AI-enabled solutions using data from enterprise systems such as SAP S/4 HANA, e-Procurement system and SCADA, to detect data anomalies, fraud indicators and process inefficiencies.\n* Partner business units and digital teams to understand end-to-end processes in procurement, finance, operations & maintenance, and risk, and translate them into analytical or AI use cases to strengthen governance.\n* Partner auditors to analyse large data sets and design data-driven audit procedures to enhance auditor’s effectiveness and efficiency.\n* Perform or assist in cybersecurity/ process audits, if required.\n\n**Requirements:**\n\n* Bachelor’s degree in Data Science, Computer Science, Engineering, Information Technology or a related quantitative discipline.\n* Minimum 5 years of hands-on experience in a data analytics and data science.\n* Practical experience applying machine learning and/or leveraging generative AI to real business problems is advantageous.\n* Strong Python programming skills for data wrangling, machine learning frameworks and automation.\n* Proficient in database querying and job scheduling tools.\n* Familiarity with SAP S/4 HANA data structures and Diligent HighBond, ACL or other audit analytics tools is advantageous.\n* Sound understanding of procurement, finance and operational & maintenance processes.\n* Ability to evaluate control adequacy and effectiveness using data-driven approaches.\n* Strong communication skills; able to explain complex analytics to non-technical audience.\n* Collaborative, with the ability to influence and partner across functions.\n* Analytical mindset, with strong problem‑solving and critical thinking skills.\n* Comfortable working independently in a fast-paced environment.\n* Willingness to assist in audits related to IT/OT cybersecurity and business processes\n\n**Our Culture at Sembcorp**\n\nAt Sembcorp, our culture is shaped by a strong set of shared behaviours that guide the way we work and uphold our commitment to driving the energy transition.\n\nWe foster an institution-first mindset, where the success of Sembcorp takes precedence over individual interests. Collaboration is at the heart of what we do, as we work seamlessly across markets, businesses, and functions to achieve our goals together. Accountability is a core principle, ensuring that we take ownership of our commitments and deliver on them with integrity and excellence. These values define who we are and create a workplace where our people can thrive while making a meaningful impact on driving energy transition.\n\nJoin us in making a real impact!\n\n**Job Snapshot**\n\nUpdated Date\n\n19-03-2026\n\nJob ID\n\nJob ID3876\n\nDepartment\n\nGroup Integrated Audit\n\nLocation\n\nSingapore, Central, Singapore\n\nExperience\n\n5 - 7 Years\n\nEmployee Type\n\nPermanent", "requirements": "Minimum 5 years of hands-on experience in data analytics and data science. Practical experience applying machine learning and/or leveraging generative AI to real business problems is advantageous. Strong Python programming skills for data wrangling, machine learning frameworks and automation.", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Data Analyst", "relevance_score": 35, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "标题命中: data", "描述命中: data", "标题命中: analyst", "描述命中: analyst", "描述命中: science", "描述命中: business", "描述命中: insights"], "market_country": "新加坡", "skill_evidence": [{"name": "Python Programming", "evidence": "Strong Python programming skills for data wrangling, machine learning frameworks and automation."}, {"name": "Machine Learning Frameworks", "evidence": "Strong Python programming skills for data wrangling, machine learning frameworks and automation."}, {"name": "Generative AI", "evidence": "Practical experience applying machine learning and/or leveraging generative AI to real business problems is advantage..."}, {"name": "Database Querying", "evidence": "Proficient in database querying and job scheduling tools."}, {"name": "Job Scheduling Tools", "evidence": "Proficient in database querying and job scheduling tools."}, {"name": "SAP S/4 HANA", "evidence": "Familiarity with SAP S/4 HANA data structures and Diligent HighBond, ACL or other audit analytics tools is advantageous."}, {"name": "Diligent HighBond", "evidence": "Familiarity with SAP S/4 HANA data structures and Diligent HighBond, ACL or other audit analytics tools is advantageous."}, {"name": "ACL", "evidence": "Familiarity with SAP S/4 HANA data structures and Diligent HighBond, ACL or other audit analytics tools is advantageous."}, {"name": "Data Wrangling", "evidence": "Strong Python programming skills for data wrangling, machine learning frameworks and automation."}, {"name": "Automated Data Pipelines", "evidence": "Operate and enhance the existing continuous assurance program (data analytics), including case management processes,..."}, {"name": "Case Management Processes", "evidence": "Operate and enhance the existing continuous assurance program (data analytics), including case management processes,..."}], "skills": ["Python Programming", "Machine Learning Frameworks", "Generative AI", "Database Querying", "Job Scheduling Tools", "SAP S/4 HANA", "Diligent HighBond", "ACL", "Data Wrangling", "Automated Data Pipelines", "Case Management Processes"]}, {"title": "Analyst/Associate, Sourcing Specialist (12 months contract)", "company": "GIC", "salary": "面议", "location": "S00", "experience": "1-3年", "education": "不限", "description": "**Location:**Singapore, SG\n\n**Job Function:** Human Resource & Organization Department\n\n**Job Type:** Contract\n\n**Req ID:** 17068\n\nGIC is one of the world’s largest sovereign wealth funds. With over 2,000 employees across 11 offices around the world, we invest in more than 40 countries globally across asset classes and businesses. Working at GIC gives you exposure to an extraordinary network of the world’s industry leaders. As a leading global long-term investor, we Work at the Point of Impact for Singapore’s financial future, and the communities we invest in worldwide.\n\n  \n\n**Human Resource & Organization Department**  \nWe drive GIC’s talent strategies, and shape the organisational culture to sustain GIC’s long-term performance.\n\n  \n\n**Talent Acquisition**  \nYou will find, assess, and hire candidates to fill open positions within GIC.\n\n  \n\n**What impact can you make in this role?**  \nYou will be part of a team that champions the people agenda for GIC.\n\n  \n\n**What will you do as a Sourcing Specialist?**\n\n* Partner with recruiters to understand role requirements and translate them into effective, data-backed sourcing strategies.\n* Support multiple searches simultaneously by building and refreshing candidate pipelines\n* Conduct talent mapping exercises and gather market intelligence to inform our decision-making process\n* Conduct initial outreach and screening conversations to assess candidate interest and suitability. Ensure smooth handover of qualified candidates to recruiters for further evaluation and interviews.\n* Contribute to the continuous improvement of Talent Acquisition processes, tools, and systems, leveraging data and insights to enhance efficiency, candidate experience, and overall recruitment effectiveness.\n\n  \n\n**What qualifications or skills should you possess in this role?**\n\n* Minimum 2 years of experience in talent sourcing, research, or recruitment coordination.\n* Strong research and analytical skills with the ability to map complex talent markets and extract actionable insights.\n* Strong communication and stakeholder management skills; comfortable engaging passive candidates and senior stakeholders alike.\n* Proficient in using various research/sourcing tools to identify and engage candidates\n\n  \n\n**Work at the Point of Impact**  \nWe need to be forward-looking to attract the right people to help us become the Leading Global Long-term Investor. Join our ambitious, agile, and diverse teams - be empowered to push boundaries and pursue innovative ideas, share your views, and be heard. Be anchored on our PRIME Values: Prudence, Respect, Integrity, Merit and Excellence, which guides us in how we make our day-to-day decisions. We strive to inspire. To make an impact.\n\n  \n\n**Flexibility at GIC**  \nAt GIC, our offices are vibrant hubs for ideation, professional growth, and interpersonal connection. At the same time, we believe that flexibility allows us to do our best work and be our best selves. Thus, our teams come into the office four days per week to harness the benefits of in-person collaboration, but have the flexibility to choose which days they work from home and adjust this arrangement as situational needs arise.\n\n  \n\n**GIC is an equal opportunity employer**\n\nGIC is an equal opportunity employer, and we value diversity. We do not discriminate based on race, religion, color, national origin, sex, gender, gender expression, sexual orientation, age, marital status, veteran status, or disability status. We will ensure that individuals with disabilities are provided reasonable accommodation to participate in the job application or interview process, to perform essential job functions, and to receive other benefits and privileges of employment.\n\n  \n\n**Learn more about our Human Resource & Organisation Department here:**  \nhttps://gic.careers/group/human-resource-organization/", "requirements": "具备至少2年的招聘、人才搜寻或招聘协调经验；熟练使用各种招聘和人才搜寻工具；能够进行复杂人才市场的研究并提取可操作的见解。", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Business Intelligence Analyst", "relevance_score": 35, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "描述命中: data", "标题命中: analyst", "描述命中: business", "描述命中: intelligence", "描述命中: insights", "标题命中: specialist", "描述命中: specialist"], "market_country": "新加坡", "skill_evidence": [{"name": "research/sourcing tools", "evidence": "Proficient in using various research/sourcing tools to identify and engage candidates"}], "skills": ["research/sourcing tools"]}, {"title": "Buy-side Enterprise Services - Risk Services Specialist - Singapore", "company": "Bloomberg", "salary": "面议", "location": "S00", "experience": "不限", "education": "不限", "description": "Buy-side Enterprise Services - Risk Services Specialist - Singapore\n\nLocation\n\nSingapore\n\nBusiness Area\n\nSales and Client Service\n\nRef #\n\n10049982\n\n**Description & Requirements**\n------------------------------\n\nBloomberg is a global leader in business and financial information, news and insight, and we use innovative technology to deliver trusted data and bring transparency to the financial markets. Our customers around the globe rely on us for the information and tools they need to make critical investment decisions and remain connected across all sides of the financial community. And, to ensure the best experience for our 26,000+ employees across more than 150 locations around the world, we provide the spaces and systems that allow our teams to work together with agility, productivity and collaboration, no matter where they are.\n\nBloomberg’s Multi-Asset Risk System (MARS) and derivatives data and valuation services (BVAL OTC) offers a comprehensive suite of risk management tools that delivers consistent, consolidated results across our client''s entire firm. MARS is powered by Bloomberg’s world-class pricing library, market data and mortgage cash flow engine, and together with BVAL OTC enables front office, risk, middle office, collateral managers, and other financial professionals to analyse their trading and investment portfolios, manage and mitigate their exposure, and ready themselves for any turn of events.\n\n**What’s the role?**\n\nWe are looking for a motivated individual with market knowledge and expertise, to support clients who use our solutions with outstanding service that allows them to operate effectively. As part of the Enterprise Risk Services team, you will work in a client facing role, liaising with portfolio managers, risk and performance analysts, and back/middle-office professionals. Being part of the team means you''ll be providing outstanding customer service, while building detailed knowledge of our solutions.\n\nOur clients rely on your domain expertise to guide them, so that they can use the power of our risk system to make better business decisions. To be successful, you will be a curious and inquisitive troubleshooter that is eager to share tips and insights about business-critical features and exciting new functionality. Whether you’re on a chat, getting on a call, or on-site with your client, you can quickly size up a situation and provide a solution.\n\n**The role can be broken down into 3 core areas:**\n\n* Client Service - At Bloomberg we pride ourselves on focusing on customer experience, providing our clients with the fastest and most knowledgeable solutions. In the role, you will use your product knowledge and acquired client intel to build and maintain credible relationships with our clients, create clear and up-to-date documentation of client needs, and communicate effectively with external stakeholders.\n* Product and Domain Expertise - Keeping up to date with market trends while understanding the impact on our clients is crucial. You will develop your knowledge of our products and customers'' workflows, sharing and building this knowledge across your team.\n* Business Impact - You''ll be involved in generating leads and contributing to sales campaigns, prioritising product enhancement requests for our Product and Engineering teams, and providing valuable customer intelligence that drives product improvements and sales performance.\n\n  \n\n**We''ll trust you to:**\n\n* Be responsible for our production client’s experience on the MARS platform, include day to day production inquiries, escalations handling, and onboarding new workflows\n* Build and maintain credible relationships with your clients, deliver client training and actively communicate with external stakeholders.\n* Foster excellent relationships with key Risk Enterprise clients to improve their overall experience in using the product\n* Develop your knowledge of our products and customers'' workflows, keep up to date with market trends, understanding the impact on our clients’ workflows and businesses, sharing and building this knowledge across your team\n* Provide feedback to the Product team on client needs, competitor intelligence and market trends.\n* Collaborate extensively with our Risk Sales, Risk Engineering, and Risk Product teams to improve our clients'' experience and overall performance of our technology\n* Identify gaps and opportunities to introduce best practices and new processes to enhance efficiency and improve on existing processes\n* Manage client expectations through timely and effective communications during systemic issues or escalations\n\n  \n\n**You''ll need to have:**\n\n* Minimum 4 years of experience in Financial Services or a Financial Technology company\n* Experience in Derivatives (from the buy-side or sell-side, or vendor selling or supporting derivatives market data and risk analytics tools)\n* Experience in building relationships across various stakeholder levels (e.g. technical contacts, product managers, traders, executive team etc.)\n* Ability to utilize your strong product knowledge, technical skills, and market knowledge to support our Enterprise clients\n* Excellent customer service skills\n* Ability to assist with product testing and project management work\n* Strong multi-tasking and prioritization skills, while being a self-starter and a proactive collaborator\n* High level of energy, creativity, flexibility, and dedication - a willingness to focus and commit to finding the best solution for our clients\n* Demonstrated continuous career growth within an organisation\n* Strong presentation and communication skills in English, with the ability to explain complex analytics and recommend best practices\n* Bachelor’s degree or degree equivalent qualifications\n\n  \n\n**We''d love to see:**\n\n* Proficiency with market practice on risk management and derivatives valuation\n* CFA or FRM qualification\n* Prior experience with mortgages (MBS, CMBS, RMBS, TBA’s, CLO’s, Pools, etc.) with an understanding of prepay assumptions in pricing models\n* Knowledge of regulations such as FRTB, SIMM, SA-CCR\n* Passion for technology and demonstrated experience with Python and/or other programming languages\n* Prior working experience with the Bloomberg suite of products\n\n  \n\n**If this sounds like you:**\n\nApply if you think we''re a good match. We''ll get in touch to let you know what the next steps are, but in the meantime feel free to have a look at this:\n\n  \n  \n\n**Why Bloomberg?**\n\nWe’re individuals with diverse backgrounds, talents, and experiences who take on big challenges and create even bigger impact through our work. We’re interested in what makes you you, and how we can create opportunities for you to channel your unique, personal energy and grow to your fullest potential.\n\n**Learn more about our office and benefits:**\n\nSingapore |\n\n  \n  \n\nBloomberg is committed to improving the communities, cities and countries in which we work, and we support various initiatives including hiring and developing local talent. So, we may prioritise candidates with legal authorisation to work full-time in Singapore for this role, who do not require Bloomberg to sponsor their work authorization.\n\nDiscover what makes Bloomberg unique - watch our for an inside look at our culture, values, and the people behind our success.", "requirements": "支持使用Bloomberg解决方案的客户，提供出色的客户服务；具备市场知识和专业知识，能够快速评估情况并提供解决方案；与关键风险企业客户建立良好关系，提升其产品使用体验。", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Big Data Analyst", "relevance_score": 33, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "描述命中: data", "描述命中: analyst", "描述命中: big", "描述命中: business", "描述命中: intelligence", "描述命中: insights", "标题命中: specialist", "描述命中: specialist"], "market_country": "新加坡", "skills": [], "skill_evidence": []}, {"title": "Data Engineer (Graph, Vector & Data Platform) - Senior Associate, AI & Data, Technology Consulting", "company": "EY", "salary": "面议", "location": "Raffles Quay", "experience": "不限", "education": "硕士及以上", "description": "At EY, we develop you with future-focused skills and equip you with world-class experiences. We empower you in a flexible environment, and fuel you and your extraordinary talents in a diverse and inclusive culture of globally connected teams.\n\nWe work together across our full spectrum of services and skills powered by technology and AI, so that businesses, people and the planet can thrive together.\n\nWe’re all in, are you?\n\nJoin EY and shape your future with confidence.\n\n### **About the opportunity**\n\nEY AI & Data is the data and advanced analytics capability within EY Asia-Pacific, with over 500 specialist employees working across multiple industry sectors. We implement information-driven strategies, data platforms, and advanced data analytics solution systems that help grow, optimize, and protect client organizations. We go beyond strategy and provide end to end design, build and implementation of real-life data environments and have some of the best architects, project managers, business analysts, data scientists, big data engineers, developers and consultants in the region.\n\nWe are seeking a Data Engineer with strong experience in graph databases, entity network analysis, and vector data platforms to design, build, and operate scalable data solutions. The role focuses on Neo4j-based graph platforms, vector databases, and modern data repositories using Apache Iceberg, running on Nutanix hybrid infrastructure, to support advanced analytics, AI, and enterprise data use cases.\n\n### **Your key responsibilities**\n\n* Design and implement graph data models and entity networks using Neo4j\n* Develop and optimize Cypher queries for relationship and network analysis\n* Build and maintain vector databases using Postgres (pgvector), Milvus, or Weaviate\n* Implement embedding ingestion pipelines for similarity and semantic search use cases\n* Design and manage data repositories / lakehouse layers using Apache Iceberg\n* Develop data ingestion and transformation pipelines from multiple source system\n* Deploy and operate databases and data platforms on Nutanix infrastructure\n* Ensure performance tuning, scalability, availability, and fault tolerance\n* Implement data quality checks, monitoring, and error handling\n* Collaborate with AI/ML, analytics, and application teams\n* Document data models, architectures, and operational procedures\n\n### **To qualify for the role, you must have**\n\n* Bachelor''s degree in computer science, Information Systems, or related field.\n* Minimally 4 years of hands-on experience in Data Engineering\n* Strong hands-on experience with Neo4j (Graph DB)\n* Proven experience in entity network analysis and relationship-based modeling\n* Hands-on experience with vector databases:\n  + Postgres (pgvector), Milvus, and/or Weaviate\n* Strong SQL skills and experience with complex data transformations\n* Experience designing data lakes / lakehouse architectures\n* Hands-on experience with Apache Iceberg or similar table formats\n* Experience operating data platforms on Nutanix or comparable on-prem / hybrid infrastructure\n* Solid understanding of distributed systems and data storage concepts\n\n### **Ideally, you’ll also have**\n\n* Python or Java for data processing and integration\n* Experience with Spark, Kafka, or Flink\n* Experience with LLM / AI pipelines and embedding generation\n* Knowledge of Elasticsearch or hybrid search architectures\n* Experience with data governance, security, and access control\n* Exposure to DevOps / CI-CD for data platforms\n\n### **What we look for**\n\n* Highly motivated individuals with excellent problem-solving skills and the ability to prioritize shifting workloads in a rapidly changing industry.\n* An effective communicator, you’ll be a confident leader equipped with strong people management skills and a genuine passion to make things happen in a dynamic organization.\n\n### **What working at EY offers**\n\nEY offers a competitive remuneration package where you’ll be rewarded for your individual and team performance. We are committed to being an inclusive employer and are happy to consider flexible working arrangements. Plus, we offer:\n\n**Continuous learning:** You’ll develop the mindset and skills to navigate whatever comes next.\n\n**Success as defined by you:** We’ll provide the tools and flexibility, so you can make a meaningful impact, your way.\n\n**Transformative leadership:** We’ll give you the insights, coaching and confidence to be the leader the world needs.\n\n**Diverse and inclusive culture**: You’ll be embraced for who you are and empowered to use your voice to help others find theirs.\n\n### \n\n### **Company description**\n\nEY is building a better working world by creating new value for clients, people, society and the planet, while building trust in capital markets.\n\nEnabled by data, AI and advanced technology, EY teams help clients shape the future with confidence and develop answers for the most pressing issues of today and tomorrow.\n\nEY teams work across a full spectrum of services in assurance, consulting, tax, strategy and transactions. Fueled by sector insights, a globally connected, multi-disciplinary network and diverse ecosystem partners, EY teams can provide services in more than 150 countries and territories.\n\nAll in to shape the future with confidence.", "requirements": "You must have strong hands-on experience with Neo4j, vector databases, and Apache Iceberg. You should also have experience designing data lakes / lakehouse architectures and operating data platforms on Nutanix or comparable on-prem / hybrid infrastructure.", "source": "Indeed", "source_warning": "部分数据源抓取失败：linkedin: 抓取超时，已跳过", "search_keyword": "Big Data Analyst", "relevance_score": 33, "relevance_reasons": ["标题部分命中: 大数据分析 / data analyst / big data analyst / data science / business intelligence analyst / data insights specialist", "标题命中: data", "描述命中: data", "描述命中: analyst", "描述命中: big", "描述命中: science", "描述命中: business", "描述命中: insights", "描述命中: specialist"], "market_country": "新加坡", "skill_evidence": [{"name": "Neo4j", "evidence": "The role focuses on Neo4j-based graph platforms"}, {"name": "Apache Iceberg", "evidence": "Design and manage data repositories / lakehouse layers using Apache Iceberg"}, {"name": "Postgres (pgvector)", "evidence": "Build and maintain vector databases using Postgres (pgvector), Milvus, or Weaviate"}, {"name": "Milvus", "evidence": "Build and maintain vector databases using Postgres (pgvector), Milvus, or Weaviate"}, {"name": "Weaviate", "evidence": "Build and maintain vector databases using Postgres (pgvector), Milvus, or Weaviate"}, {"name": "SQL", "evidence": "Strong SQL skills and experience with complex data transformations"}, {"name": "Spark", "evidence": "Experience with Spark, Kafka, or Flink"}, {"name": "Kafka", "evidence": "Experience with Spark, Kafka, or Flink"}, {"name": "Flink", "evidence": "Experience with Spark, Kafka, or Flink"}, {"name": "LLM / AI pipelines", "evidence": "Experience with LLM / AI pipelines and embedding generation"}, {"name": "Embedding Generation", "evidence": "Experience with LLM / AI pipelines and embedding generation"}, {"name": "Elasticsearch", "evidence": "Knowledge of Elasticsearch or hybrid search architectures"}, {"name": "Data Governance", "evidence": "Experience with data governance, security, and access control"}, {"name": "Security", "evidence": "Experience with data governance, security, and access control"}, {"name": "Access Control", "evidence": "Experience with data governance, security, and access control"}, {"name": "DevOps / CI-CD", "evidence": "Exposure to DevOps / CI-CD for data platforms"}], "skills": ["Neo4j", "Apache Iceberg", "Postgres (pgvector)", "Milvus", "Weaviate", "SQL", "Spark", "Kafka", "Flink", "LLM / AI pipelines", "Embedding Generation", "Elasticsearch", "Data Governance", "Security", "Access Control", "DevOps / CI-CD"]}, {"title": "Agentic AI Solution Architect, AI & Data, Technology Consulting", "company": "EY", "salary": "面议", "location": "Raffles Quay", "experience": "不限", "education": "硕士及以上", "description": "At EY, we develop you with future-focused skills and equip you with world-class experiences. We empower you in a flexible environment, and fuel you and your extraordinary talents in a diverse and inclusive culture of globally connected teams. We work together across our full spectrum of services and skills powered by technology and AI, so that business, people and the planet can thrive together. We’re all in, are you? Join EY and shape your future with confidence.\n\n**The opportunity**\n\nEY AI & Data is the data and advanced analytics capability within EY Asia-Pacific, with over 500 specialist employees working across multiple industry sectors. We implement information-driven strategies, data platforms and advanced data analytics solution systems that help grow, optimize and protect client organizations. We go beyond strategy and provide end to end design, build and implementation of real life data environments and have some of the best architects, project managers, business analysts, data scientists, big data engineers, developers and consultants in the region. We are looking for a AI Solution Architect within the AI & Data team in our Singapore office. This role is offered on a flexible full-time basis.\n\n**Your key responsibilities**\n\n* Build end-to-end Gen AI solutions - develop, refine, and implement advanced Gen AI models and ensure the success delivery of projects\n* Lead the integration of LLMs and LangChain into business processes.\n* Utilize Python and other data manipulation languages proficiently to prepare and manipulate data.\n* Understand the business requirements and translate into Gen AI solution design that successfully meets the business objectives.\n* Collaborate with stakeholders, presenting findings to a non-technical audience and providing strategic recommendations.\n* Stay current with technical and industry developments and standards to ensure effective and advanced applications of data analysis techniques and methodologies.\n\n**Skills and attributes for success**\n\n* Knowledge and experience in end-to-end project delivery, especially agile delivery methodologies or hybrid approaches\n* Agentic AI / Generative AI solution design and implementation\n* Exceptional communication, documentation and presentation skills and stakeholder management experiences\n\n**To qualify for the role, you must have**\n\n* Min Bachelor’s degree in Computer science, Mathematics, Engineering, Statistics, or a related field.\n* At least 5 years of experience with Traditional AIML, Generative AI, specifically with Large Language Models (LLM) and Langchain.\n* Proficiency in Python and other applicable programming languages.\n* Strong knowledge of machine learning, data mining, and predictive modeling.\n* Excellent understanding of machine learning algorithms, processes, tools, and platforms.\n* Possess strong problem-solving and strategic thinking abilities.\n\n**What we look for**\n\n* Highly motivated individuals with excellent problem-solving skills and the ability to prioritize shifting workloads in a rapidly changing industry.\n* An effective communicator, you’ll be a confident leader equipped with strong people management skills and a genuine passion to make things happen in a dynamic organization.\n\n**What we offer**\n\nEY offers a competitive remuneration package commensurate with your work experience where you’ll be rewarded for your individual and team performance. We are committed to being an inclusive employer and are happy to consider flexible working arrangements, where this may be needed, guided by our FWA Policy.\n\nPlus, we offer:\n\n* **Continuous learning:** You’ll develop the mindset and skills to navigate whatever comes next.\n* **Success as defined by you:** We’ll provide the tools and flexibility, so you can make a meaningful impact, your way.\n* **Transformative leadership:** We’ll give you the insights, coaching and confidence to be the leader the world needs.\n* **Diverse and inclusive culture:** You’ll be embraced for who you are and empowered to use your voice to help others find theirs.\n\n**If you can demonstrate that you meet the criteria above, apply today!**\n\nEY is building a better working world by creating new value for clients, people, society and the planet, while building trust in capital markets. Enabled by data, AI and advanced technology, EY teams help clients shape the future with confidence and develop answers for the most pressing issues of today and tomorrow. EY teams work across a full spectrum of services in assurance, consulting, tax, strategy and transactions. Fueled by sector insights, a globally connected, multi-disciplinary network and diverse ecosystem partners, EY teams can provide services in more than 150 countries and territories. All in to shape the future with confidence.\n\n**Apply now.**", "requirements": "Candidates must have at least 5 years of experience with Traditional AIML, Generative AI, specifically with Large Languag